FileUtil = {}
FileUtil.MapPath = ""

function FileUtil:setMapPath(path)
    self.MapPath = string.gsub(tostring(path), "config.yml", "")
end

function FileUtil:getMapPath()
    return self.MapPath
end

function FileUtil:getScriptDir()
    local result = "./" .. tostring(Server.Instance():getConfig().scriptDir)
    result = string.gsub(result, "\\", "\\\\")
    result = string.gsub(result, "/", "\\\\")
    return result
end

function FileUtil.getConfigFromYml(name, checkExist)
    local path = FileUtil:getMapPath() .. name
    if not string.find(name, ".yml") then
        path = path .. ".yml"
    end
    local file = io.open(path, "r")
    if not file then
        if checkExist then
            return {}
        end
        LogUtil.log("FileUtil.getConfigFromYml not file " .. path, LogUtil.LogLevel.Error)
    end
    local content = file.read(file, "*a")
    io.close(file)
    return TinyParse(content)
end

function FileUtil.getConfigFromCsv(name, row, checkExist)
    local path = FileUtil:getMapPath() .. name
    if checkExist then
        local file = io.open(path, "r")
        if not file then
            return {}
        end
    end
    row = row or 2
    return CsvUtil.loadCsvFile(path, row)
end

return FileUtil